import{_ as t,a,b as n,c as l,d as o}from"./chunks/编辑配置.T0puvWjh.js";import{_ as r,o as d,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Telegram Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/telegram.md","filePath":"bn-BD/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"bn-BD/upload/telegram.md"};function c(p,e,m,b,g,u){return d(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-channel-যোগ-করা" tabindex="-1">Telegram Channel যোগ করা <a class="header-anchor" href="#telegram-channel-যোগ-করা" aria-label="Permalink to &quot;Telegram Channel যোগ করা&quot;">​</a></h1><h2 id="শুরু-করার-আগে-যা-লাগবে" tabindex="-1">শুরু করার আগে যা লাগবে <a class="header-anchor" href="#শুরু-করার-আগে-যা-লাগবে" aria-label="Permalink to &quot;শুরু করার আগে যা লাগবে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>Bot এবং storage channel তৈরি করতে লাগে।</td></tr><tr><td><code>@BotFather</code></td><td>Telegram bot তৈরি করতে ব্যবহার হয়।</td></tr><tr><td>একটি Telegram channel</td><td>Files সংরক্ষণের final destination।</td></tr><tr><td><code>@userinfobot</code></td><td>Channel <code>Chat ID</code> বের করতে ব্যবহার হয়।</td></tr></tbody></table><h2 id="কোথায়-যোগ-করবেন" tabindex="-1">কোথায় যোগ করবেন <a class="header-anchor" href="#কোথায়-যোগ-করবেন" aria-label="Permalink to &quot;কোথায় যোগ করবেন&quot;">​</a></h2><ol><li>System Settings খুলুন।</li><li>Upload Settings-এ যান।</li><li>উপরের ডান পাশে Add Channel ক্লিক করুন।</li><li><code>Telegram</code> নির্বাচন করুন।</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>কাজ</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>এই channel-এর সহজে চেনা যায় এমন নাম, যেমন &quot;Telegram Primary&quot;।</td><td>Required</td></tr><tr><td>Active</td><td>Channel enable বা disable করে।</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>আপনার Telegram bot-এর token।</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>Telegram channel-এর ID।</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Telegram access unstable হলে শুধু তখন ব্যবহার করুন। <code>https://</code>-সহ full proxy URL দিন।</td><td>Optional</td></tr><tr><td>Remark</td><td>ভবিষ্যৎ maintenance-এর জন্য notes।</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-telegram-bot-তৈরি-করুন" tabindex="-1">1. Telegram Bot তৈরি করুন <a class="header-anchor" href="#_1-telegram-bot-তৈরি-করুন" aria-label="Permalink to &quot;1. Telegram Bot তৈরি করুন&quot;">​</a></h3><ol><li>Telegram খুলে <code>@BotFather</code> search করুন।</li><li>Chat খুলে <code>Start</code> ক্লিক করুন।</li><li><code>/newbot</code> পাঠান।</li><li>Prompt অনুযায়ী bot display name দিন।</li><li>Prompt অনুযায়ী bot username দিন। Username সাধারণত <code>bot</code> দিয়ে শেষ করতে হয়।</li><li>Bot তৈরি হলে <code>@BotFather</code> একটি bot token দেবে।</li></ol><p>এই token-টাই ImgBed-এ <code>Bot Token</code> হিসেবে দিতে হবে।</p><p><img src="'+t+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-channel-তৈরি-করুন" tabindex="-1">2. Channel তৈরি করুন <a class="header-anchor" href="#_2-channel-তৈরি-করুন" aria-label="Permalink to &quot;2. Channel তৈরি করুন&quot;">​</a></h3><ol><li>Telegram-এ New Channel ক্লিক করুন।</li><li>Channel name দিন।</li><li>Channel তৈরি শেষ করুন।</li></ol><p>Public এবং private, দুই ধরনের channel-ই ব্যবহার করা যায়।</p><p><img src="'+a+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-bot-কে-channel-এ-যোগ-করুন" tabindex="-1">3. Bot-কে Channel-এ যোগ করুন <a class="header-anchor" href="#_3-bot-কে-channel-এ-যোগ-করুন" aria-label="Permalink to &quot;3. Bot-কে Channel-এ যোগ করুন&quot;">​</a></h3><ol><li>সদ্য তৈরি করা channel খুলুন।</li><li>Channel settings খুলুন।</li><li>Member বা administrator যোগ করুন।</li><li>আপনার তৈরি করা bot username search করুন।</li><li>Bot-কে channel-এ যোগ করুন।</li></ol><p>Upload সবচেয়ে নির্ভরযোগ্য করতে bot-কে administrator permission দিন।</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-user-info-get-id-idbot-দিয়ে-channel-id-নিন" tabindex="-1">4. User Info - Get ID - IDbot দিয়ে Channel ID নিন <a class="header-anchor" href="#_4-user-info-get-id-idbot-দিয়ে-channel-id-নিন" aria-label="Permalink to &quot;4. User Info - Get ID - IDbot দিয়ে Channel ID নিন&quot;">​</a></h3><ol><li>Telegram-এ <code>@userinfobot</code> search করুন। Display name সাধারণত <code>User Info - Get ID - IDbot</code>।</li><li>Chat খুলে <code>Start</code> ক্লিক করুন।</li><li>Bot-এর দেওয়া options থেকে <code>Channel</code> নির্বাচন করুন।</li><li>Message picker-এ target channel নির্বাচন করে <code>@userinfobot</code>-এ পাঠান।</li><li><code>@userinfobot</code> result দিলে <code>Id: -100...</code> হিসেবে যে number দেখায় সেটি copy করুন।</li></ol><p><code>-100</code> দিয়ে শুরু হওয়া number-টাই ImgBed-এর জন্য প্রয়োজনীয় <code>Session ID (Chat ID)</code>।</p><p><img src="'+l+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-imgbed-এ-telegram-channel-পূরণ-করুন" tabindex="-1">5. ImgBed-এ Telegram Channel পূরণ করুন <a class="header-anchor" href="#_5-imgbed-এ-telegram-channel-পূরণ-করুন" aria-label="Permalink to &quot;5. ImgBed-এ Telegram Channel পূরণ করুন&quot;">​</a></h3><p>Channel configuration dialog-এ ফিরে এসে fields এভাবে পূরণ করুন:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Custom channel name, যেমন <code>TelegramPrimary</code>।</td></tr><tr><td>Active</td><td>Recommended।</td></tr><tr><td>Bot Token</td><td><code>@BotFather</code> থেকে পাওয়া bot token।</td></tr><tr><td>Session ID (Chat ID)</td><td><code>@userinfobot</code> থেকে পাওয়া <code>-100...</code> number।</td></tr><tr><td>Relay Proxy URL (optional)</td><td>দরকার হলে, যেমন <code>https://your-tg-proxy.example.com</code>।</td></tr><tr><td>Remark</td><td>Optional notes।</td></tr></tbody></table><p>শেষ হলে Save ক্লিক করুন।</p><p><img src="'+o+`" alt="Edit the configuration" loading="lazy"></p><h2 id="কীভাবে-যাচাই-করবেন" tabindex="-1">কীভাবে যাচাই করবেন <a class="header-anchor" href="#কীভাবে-যাচাই-করবেন" aria-label="Permalink to &quot;কীভাবে যাচাই করবেন&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>কীভাবে যাচাই করবেন</th></tr></thead><tbody><tr><td>Channel card দেখা যায়</td><td>Save করার পর Upload Settings পেজে Telegram channel card দেখা উচিত।</td></tr><tr><td>Channel enable থাকে</td><td>Active switch on থাকা উচিত।</td></tr><tr><td>Configuration save হয়েছে</td><td>Detail view-তে Bot Token এবং Chat ID save হয়েছে দেখা উচিত।</td></tr><tr><td>Upload কাজ করে</td><td>একটি test image upload করে target Telegram channel-এ এসেছে কি না দেখুন।</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@BotFather দিয়ে bot তৈরি করুন</span></span>
<span class="line"><span>-&gt; Bot Token save করুন</span></span>
<span class="line"><span>-&gt; Telegram channel তৈরি করুন</span></span>
<span class="line"><span>-&gt; Bot-কে channel-এ যোগ করে administrator permission দিন</span></span>
<span class="line"><span>-&gt; @userinfobot search করে Channel নির্বাচন করুন</span></span>
<span class="line"><span>-&gt; Channel থেকে যেকোনো message @userinfobot-এ forward করুন</span></span>
<span class="line"><span>-&gt; ফেরত পাওয়া Id: -100... copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ Bot Token এবং Chat ID দিন</span></span>
<span class="line"><span>-&gt; Save করে test image upload করুন</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const k=r(h,[["render",c]]);export{_ as __pageData,k as default};
